const GROUP_MAP = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly' },
  '120363420996892188@g.us': { context: 'garlic',   label: 'Garlic N Lemon' },
  '120363422948599063@g.us': { context: 'ernesto',  label: 'Ernesto' },
};

const raw  = $input.first().json;
const body = raw.body || raw;

const debugKeys = Object.keys(body || {}).join(', ');
const debugData = body?.data ? Object.keys(body.data).join(', ') : 'n/a';

const messageText =
  body?.text ||
  body?.message?.text ||
  body?.message?.body ||
  body?.data?.text ||
  body?.data?.message?.text ||
  body?.data?.message?.body ||
  body?.data?.message?.conversation ||
  body?.data?.message?.extendedTextMessage?.text ||
  '';

const senderName =
  body?.senderName ||
  body?.message?.senderName ||
  body?.data?.senderName ||
  body?.sender?.pushname ||
  body?.data?.pushName ||
  'Unknown';

const chatId =
  body?.chatid ||
  body?.chatId ||
  body?.wa_chatid ||
  body?.waChatId ||
  body?.remoteJid ||
  body?.data?.key?.remoteJid ||
  body?.data?.message?.key?.remoteJid ||
  body?.message?.key?.remoteJid ||
  body?.id ||
  body?.data?.chatid ||
  body?.data?.chatId ||
  body?.data?.wa_chatid ||
  body?.data?.remoteJid ||
  body?.message?.chatid ||
  body?.message?.chatId ||
  body?.message?.remoteJid ||
  '';

const groupInfo = GROUP_MAP[chatId] || { context: 'unknown', label: 'Unknown' };
const cleanMessage = String(messageText || '')
  .replace(/@jarvis/ig, '')
  .replace(/\bjarvis\b/ig, '')
  .replace(/59739253801103/g, '')
  .replace(/@\w+/g, '')
  .trim();

return [{ json: {
  rawMessage: messageText,
  cleanMessage,
  senderName,
  chatId,
  waChatId: chatId,
  groupContext: groupInfo.context,
  groupLabel: groupInfo.label,
  timestamp: new Date().toISOString(),
  _debug_keys: debugKeys,
  _debug_data_keys: debugData
}}];

const inputData = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.groupMemory = staticData.groupMemory || {};

const pm = $('Check Personality Command').first().json;
const ctx = $('Build Context').first().json;
const chatId = pm.chatId || pm.waChatId || 'unknown';
const currentMessage = pm.cleanMessage || pm.rawMessage || '';
const replyTarget = pm.waChatId || pm.chatId || '120363426390515923@g.us';

if (!staticData.groupMemory[chatId]) {
  staticData.groupMemory[chatId] = {
    messages: [],
    lastProjectId: null,
    lastProjectName: '',
    pendingTask: null,
    pendingTicket: null,
    pendingQuote: null,
  };
}
const chatMemory = staticData.groupMemory[chatId];

const normalize = (v) => String(v || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const m = normalize(currentMessage);
const PARSE_VERSION = '2026-04-22-v7';

let parsed = { intent: 'none', entity: {}, reply: '' };
let responseText = '';
if (inputData?.message?.content) responseText = inputData.message.content;
else if (inputData?.choices?.[0]?.message?.content) responseText = inputData.choices[0].message.content;
else if (typeof inputData?.text === 'string') responseText = inputData.text;
else responseText = JSON.stringify(inputData || {});

try {
  const clean = responseText.replace(/\u0060\u0060\u0060json/g, '').replace(/\u0060\u0060\u0060/g, '').trim();
  const match = clean.match(/({[\s\S]*})/);
  const obj = JSON.parse(match ? match[1] : clean);
  parsed = { intent: obj.intent || 'none', entity: obj.entity || {}, reply: obj.reply || '' };
} catch (e) {}

let knownProjects = [];
try { knownProjects = JSON.parse(ctx.projectsList || '[]'); } catch (e) { knownProjects = []; }

const overlapScore = (a, b) => {
  const aa = normalize(a).split(' ').filter(x => x.length > 2);
  const bb = normalize(b).split(' ').filter(x => x.length > 2);
  if (!aa.length || !bb.length) return 0;
  const sb = new Set(bb);
  const hits = aa.filter(x => sb.has(x)).length;
  return hits / Math.max(aa.length, bb.length);
};

const findProjectByName = (name, pool = knownProjects) => {
  const target = normalize(name);
  if (!target || !pool.length) return null;

  let direct = pool.find(p => normalize(p.name) === target);
  if (direct) return direct;

  direct = pool.find(p => {
    const pn = normalize(p.name);
    return pn.includes(target) || target.includes(pn);
  });
  if (direct) return direct;

  let best = null;
  let bestScore = 0;
  for (const p of pool) {
    const s = overlapScore(target, p.name);
    if (s > bestScore) {
      bestScore = s;
      best = p;
    }
  }
  return bestScore >= 0.34 ? best : null;
};

const inferProjectFromMessage = (message, pool = knownProjects) => {
  const msg = normalize(message);
  if (!msg || !pool.length) return null;
  const hits = pool.filter(p => {
    const pn = normalize(p.name);
    return pn && (msg.includes(pn) || pn.split(' ').some(w => w.length > 3 && msg.includes(w)));
  });
  return hits.length === 1 ? hits[0] : null;
};

const groupClient = pm.groupContext === 'garlic' ? 'garlic' : (pm.groupContext === 'ernesto' ? 'ernesto' : '');
const groupProjects = groupClient
  ? knownProjects.filter(p => normalize(p.client_name).includes(groupClient) || normalize(p.name).includes(groupClient))
  : [];

const pickCanonicalGroupProject = () => {
  if (!groupProjects.length) return null;
  if (pm.groupContext === 'ernesto') {
    const p = groupProjects.find(x => /ernesto\s+s\s+pizza|ernesto s pizza|ernesto pizza/.test(normalize(x.name)));
    if (p) return p;
  }
  if (pm.groupContext === 'garlic') {
    const p = groupProjects.find(x => /garlic/.test(normalize(x.name)));
    if (p) return p;
  }
  if (pm.groupContext === 'angelfly') {
    const p = groupProjects.find(x => /angel\s*fly|cockpit/.test(normalize(x.name)));
    if (p) return p;
  }
  return null;
};

const resolveProject = (entity, { allowFallback = true } = {}) => {
  if (!knownProjects.length) return null;

  if (entity.project_name) {
    const byNameInGroup = groupProjects.length ? findProjectByName(entity.project_name, groupProjects) : null;
    if (byNameInGroup) return byNameInGroup;

    const byNameGlobal = findProjectByName(entity.project_name, knownProjects);
    if (byNameGlobal) return byNameGlobal;
  }

  if (entity.project_id) {
    const byId = knownProjects.find(p => String(p.id) === String(entity.project_id));
    if (byId) return byId;
  }

  const byMsgInGroup = groupProjects.length ? inferProjectFromMessage(currentMessage, groupProjects) : null;
  if (byMsgInGroup) return byMsgInGroup;

  const byMsgGlobal = inferProjectFromMessage(currentMessage, knownProjects);
  if (byMsgGlobal) return byMsgGlobal;

  if (!allowFallback) return null;

  if (groupProjects.length === 1) return groupProjects[0];

  const canonical = pickCanonicalGroupProject();
  if (canonical) return canonical;

  if (ctx.defaultProjectId) {
    const byCtx = knownProjects.find(p => String(p.id) === String(ctx.defaultProjectId));
    if (byCtx) return byCtx;
  }

  if (chatMemory.lastProjectId) {
    const byMem = knownProjects.find(p => String(p.id) === String(chatMemory.lastProjectId));
    if (byMem) return byMem;
  }

  return null;
};

const cleanupTitle = (txt) => String(txt || '')
  .replace(/@\w+/g, '')
  .replace(/\b(jarvis|angel fly|angelfly)\b/ig, '')
  .replace(/\b(cria|crie|abre|abrir|gera|gerar|registre|registrar|adicione|adicionar|mande|mostrar|mostra|listar|lista)\b/ig, '')
  .replace(/\b(um|uma|o|a|de|do|da|pra|para|os|as)\b/ig, ' ')
  .replace(/\b(ticket|tickets|chamado|chamados|task|tarefa|tarefas|orcamento|orcamento|orcamentos|orcamentos|quote)\b/ig, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const entity = { ...(parsed.entity || {}) };

const isMemoryStatusQuery = /(memoria|memória)/.test(m) && /(como|qual|ta|esta|status|lembr)/.test(m);
const isMemoryFirstQuery = /(primeira|primeiro).*(mensagem|texto).*(hoje|dia)/.test(m) || /(qual foi a primeira mensagem)/.test(m);

const quoteAction = /(orcamento|orçamento|quote|cotacao|cotação)/.test(m) && /(cria|crie|fazer|montar|gerar|abre|abrir|novo|criar|registrar|registre)/.test(m);

const isReport = /(quais|listar|lista|resumo|relatorio|relatório|status|ativos|ativas|abertos|abertas|quantas|quantos|temos|mande)/.test(m)
  && /(task|tarefas|ticket|tickets|chamado|chamados|cockpit)/.test(m);

const ticketAction = /((cria|crie|abrir|abre|registrar|registre|gerar|gera|adicionar|adicione).*(ticket|tickets|chamado|chamados))|((ticket|tickets|chamado|chamados).*(cria|crie|abrir|abre|registrar|registre|gerar|gera|adicionar|adicione))/.test(m)
  || /\b(abrir|abre|criar|cria)\s+um\s+bug\b/.test(m);

const taskAction = /((cria|crie|adicionar|adicione|gerar|gera).*(task|tarefa))|((task|tarefa).*(cria|crie|adicionar|adicione|gerar|gera))/.test(m);

const projectAction = /(novo projeto|criar projeto|crie projeto)/.test(m);
const paymentInAction = /(payment incoming|entrada|recebimento)/.test(m) && /(cria|crie|registrar|registre|gerar|gera)/.test(m);
const paymentOutAction = /(payment outgoing|saida|saída|pagamento)/.test(m) && /(cria|crie|registrar|registre|gerar|gera)/.test(m);

let finalIntent = 'none';
if (isMemoryStatusQuery || isMemoryFirstQuery) finalIntent = 'none';
else if (quoteAction) finalIntent = 'create_quote';
else if (isReport) finalIntent = 'fetch_report';
else if (ticketAction) finalIntent = 'create_ticket';
else if (taskAction) finalIntent = 'create_task';
else if (projectAction) finalIntent = 'create_project';
else if (paymentInAction) finalIntent = 'create_payment_incoming';
else if (paymentOutAction) finalIntent = 'create_payment_outgoing';

const parsedIntent = normalize(parsed.intent || '').replace(/\s+/g, '_');
const parsedToIntent = {
  fetch_report: 'fetch_report',
  report: 'fetch_report',
  relatorio: 'fetch_report',
  consulta: 'fetch_report',
  listar_tasks: 'fetch_report',
  listar_tickets: 'fetch_report',
  create_ticket: 'create_ticket',
  ticket: 'create_ticket',
  criar_ticket: 'create_ticket',
  chamado: 'create_ticket',
  create_task: 'create_task',
  task: 'create_task',
  criar_tarefa: 'create_task',
  tarefa: 'create_task',
  create_project: 'create_project',
  project: 'create_project',
  criar_projeto: 'create_project',
  create_payment_incoming: 'create_payment_incoming',
  create_payment_outgoing: 'create_payment_outgoing',
  create_quote: 'create_quote',
  quote: 'create_quote',
};

if ((finalIntent === 'none' || finalIntent === 'create_quote') && parsedToIntent[parsedIntent]) {
  finalIntent = parsedToIntent[parsedIntent];
}

if (isReport) finalIntent = 'fetch_report';
if (ticketAction) finalIntent = 'create_ticket';
if (taskAction && !ticketAction) finalIntent = 'create_task';

const retryHint = /(^|\s)(consegue|agora|agora sim|pode|vai|segue|manda ver|tenta de novo|retry|sim)(\s|$)/i.test(currentMessage);
if (finalIntent === 'none' && (chatMemory.pendingTask || chatMemory.pendingTicket || chatMemory.pendingQuote) && retryHint) {
  if (chatMemory.pendingTask) {
    finalIntent = 'create_task';
    Object.assign(entity, chatMemory.pendingTask);
  } else if (chatMemory.pendingTicket) {
    finalIntent = 'create_ticket';
    Object.assign(entity, chatMemory.pendingTicket);
  } else if (chatMemory.pendingQuote) {
    finalIntent = 'create_quote';
    Object.assign(entity, chatMemory.pendingQuote);
  }
}

let forcedReply = '';
let resolvedProject = null;

if (isMemoryFirstQuery) {
  const today = new Date().toISOString().slice(0, 10);
  const msgs = Array.isArray(chatMemory.messages) ? chatMemory.messages : [];
  const todays = msgs.filter(x => x && x.ts && new Date(x.ts).toISOString().slice(0, 10) === today);
  const first = (todays[0] || msgs[0] || null);
  if (first && first.text) {
    forcedReply = 'A primeira mensagem registrada hoje foi: "' + first.text + '".';
  } else {
    forcedReply = 'Ainda não tenho mensagem anterior salva para este chat hoje.';
  }
  finalIntent = 'none';
}

if (!forcedReply && isMemoryStatusQuery) {
  const msgs = Array.isArray(chatMemory.messages) ? chatMemory.messages : [];
  const lastProject = chatMemory.lastProjectName || 'não definido';
  forcedReply = 'Memória ativa neste grupo: ' + msgs.length + ' mensagens recentes salvas. Último projeto usado: ' + lastProject + '.';
  finalIntent = 'none';
}

if (finalIntent === 'create_quote') {
  const pending = chatMemory.pendingQuote || {};
  const amountMatch = currentMessage.match(/(?:r\$|\$)\s*([0-9]+(?:[\.,][0-9]{1,2})?)/i);
  if (!entity.amount && amountMatch) {
    entity.amount = Number(String(amountMatch[1]).replace(',', '.'));
  }
  if (!entity.title && !entity.subject) {
    entity.title = cleanupTitle(currentMessage) || '';
  }
  if (!entity.client_name) {
    entity.client_name = pm.groupContext === 'garlic'
      ? 'Garlic N Lemon'
      : pm.groupContext === 'ernesto'
        ? 'Ernesto Pizza'
        : '';
  }

  const merged = {
    title: entity.title || entity.subject || pending.title || '',
    description: entity.description || pending.description || '',
    client_name: entity.client_name || pending.client_name || '',
    amount: entity.amount || pending.amount || null,
    valid_until: entity.valid_until || pending.valid_until || '',
  };

  chatMemory.pendingQuote = merged;

  const missing = [];
  if (!merged.client_name) missing.push('cliente');
  if (!merged.title) missing.push('título/escopo');
  if (!merged.amount) missing.push('valor total');
  if (!merged.valid_until) missing.push('validade (data)');

  if (missing.length > 0) {
    forcedReply = 'Para montar o orçamento, me envie: ' + missing.join(', ') + '.';
  } else {
    forcedReply = 'Perfeito. Tenho os dados do orçamento. Hoje a API do Cockpit não expõe criação em /quotes; posso registrar isso agora como task no projeto e te devolver o resumo pronto para colar no módulo de Quotes.';
  }
  finalIntent = 'none';
}

if (finalIntent === 'create_task') {
  if (!entity.title) entity.title = cleanupTitle(currentMessage) || 'Task via WhatsApp';
  if (!entity.description) entity.description = currentMessage;
  entity.priority = entity.priority || 'medium';

  resolvedProject = resolveProject(entity, { allowFallback: true });
  if (resolvedProject) {
    entity.project_id = resolvedProject.id;
    entity.project_name = resolvedProject.name;
    chatMemory.lastProjectId = resolvedProject.id;
    chatMemory.lastProjectName = resolvedProject.name;
    chatMemory.pendingTask = null;
  } else {
    chatMemory.pendingTask = {
      title: entity.title || '',
      description: entity.description || '',
      priority: entity.priority || 'medium',
      project_name: entity.project_name || '',
    };
    finalIntent = 'none';
  }
}

if (finalIntent === 'create_ticket') {
  if (!entity.subject && !entity.title) entity.subject = cleanupTitle(currentMessage) || 'Ticket via WhatsApp';
  if (!entity.description) entity.description = currentMessage;
  entity.priority = entity.priority || 'medium';
  entity.category = (entity.category || 'question').toLowerCase();

  resolvedProject = resolveProject(entity, { allowFallback: true });
  if (resolvedProject) {
    entity.project_id = resolvedProject.id;
    entity.project_name = resolvedProject.name;
    chatMemory.lastProjectId = resolvedProject.id;
    chatMemory.lastProjectName = resolvedProject.name;
  } else if (knownProjects.length > 0) {
    chatMemory.pendingTicket = {
      subject: entity.subject || entity.title || '',
      description: entity.description || '',
      priority: entity.priority || 'medium',
      category: entity.category || 'question',
      project_name: entity.project_name || '',
    };
    finalIntent = 'none';
  }

  chatMemory.pendingTask = null;
}

if (finalIntent === 'fetch_report') {
  entity.scope = entity.scope || (/hoje/.test(m) ? 'today' : (/abert|ativas|ativos|pendente/.test(m) ? 'open' : 'all'));
  entity.target = entity.target || (/(task|tarefa)/.test(m) && /(ticket|chamado)/.test(m)
    ? 'both'
    : (/(ticket|chamado)/.test(m) ? 'tickets' : (/(task|tarefa)/.test(m) ? 'tasks' : 'both')));

  const msgProject = inferProjectFromMessage(currentMessage, knownProjects);
  const explicitProjectCue = !!entity.project_id || !!entity.project_name || /\b(projeto|project|id\s*[0-9]+)\b/.test(m) || !!msgProject;

  if (explicitProjectCue) {
    const seed = { ...entity };
    if (msgProject) {
      seed.project_id = seed.project_id || msgProject.id;
      seed.project_name = seed.project_name || msgProject.name;
    }
    resolvedProject = resolveProject(seed, { allowFallback: false });
    if (resolvedProject) {
      entity.project_id = resolvedProject.id;
      entity.project_name = resolvedProject.name;
      chatMemory.lastProjectId = resolvedProject.id;
      chatMemory.lastProjectName = resolvedProject.name;
    }
  } else {
    entity.project_id = null;
    entity.project_name = '';
  }
}

if (finalIntent !== 'create_ticket') chatMemory.pendingTicket = null;
if (finalIntent !== 'create_quote' && !forcedReply) chatMemory.pendingQuote = null;

const clientName = entity.client_name ||
  (pm.groupContext === 'garlic' ? 'Garlic N Lemon' :
   pm.groupContext === 'ernesto' ? 'Ernesto Pizza' : 'Angel Fly');

let reply = '';
if (forcedReply) {
  reply = forcedReply;
} else if (finalIntent === 'none') {
  if (chatMemory.pendingTask) {
    reply = knownProjects.length > 0
      ? '⚠️ Não consegui identificar o projeto da task. Me diga o projeto exato ou confirme que uso o padrão do grupo.'
      : '⚠️ Não consegui carregar os projetos do Cockpit agora. Tenta novamente em instantes.';
  } else if (chatMemory.pendingTicket) {
    reply = knownProjects.length > 0
      ? '⚠️ Não consegui identificar o projeto do ticket. Me diga o projeto exato ou confirme que uso o padrão do grupo.'
      : '⚠️ Não consegui carregar os projetos do Cockpit agora. Tenta novamente em instantes.';
  } else {
    reply = parsed.reply || 'Entendido!';
  }
} else if (finalIntent === 'fetch_report') {
  reply = 'Consultando Cockpit para montar o relatório...';
} else {
  reply = 'Processando sua solicitação...';
}

return [{ json: {
  intent: finalIntent,
  entity,
  title: entity.title || entity.subject || '',
  description: entity.description || '',
  priority: entity.priority || 'medium',
  project_id: entity.project_id || null,
  project_name: entity.project_name || '',
  subject: entity.subject || entity.title || '',
  category: entity.category || 'question',
  client_name: clientName,
  amount: entity.amount || 0,
  reply,
  senderName: pm.senderName,
  chatId: pm.chatId,
  waChatId: replyTarget,
  groupContext: pm.groupContext,
  groupLabel: pm.groupLabel,
  _debug_version: PARSE_VERSION,
  _debug_intent: {
    finalIntent,
    parsedIntent,
    isReport,
    ticketAction,
    taskAction,
    quoteAction,
    isMemoryStatusQuery,
    isMemoryFirstQuery,
  }
}}];

