={{ (() => {
  const current = $json || {};
  const source = $('Check Personality Command').isExecuted ? ($('Check Personality Command').first().json || {}) : {};

  let intent = current.intent || 'none';
  if (intent === 'none') {
    if ((current.subject || current.category) && !current.title) intent = 'create_ticket';
    else if (current.title && !current.subject) intent = 'create_task';
    else if (current.name && current.status) intent = 'create_project';
  }

  const number = current.waChatId || current.chatId || source.waChatId || source.chatId;
  let text = current.reply || 'Entendido!';

  const hasError = !!current.error;
  const errMsg = (current.error && (current.error.message || String(current.error))) || current.message || '';
  const createdId = current.id || (current.data && current.data.id);

  if (hasError) {
    text = '⚠️ *Jarvis:* ação não pôde ser concluída.\n\nErro: ' + (errMsg || 'Falha na API do Cockpit.');
  } else if (createdId) {
    if (intent === 'create_task') {
      text = '✅ Tarefa criada com sucesso no projeto "' + (current.project_name || 'selecionado') + '".';
    } else if (intent === 'create_ticket') {
      text = '🎫 Ticket registrado com sucesso para ' + (current.client_name || 'cliente') + '.';
    } else if (intent === 'create_project') {
      text = '🚀 Projeto criado com sucesso: "' + (current.name || current.project_name || 'novo projeto') + '".';
    } else {
      text = '✅ Ação concluída com sucesso no Cockpit.';
    }
  }

  return JSON.stringify({ number, text });
})() }}

