const msg = $input.first().json.cleanMessage.toLowerCase();

// Detect personality adjustment commands
const isPersonalityCmd = (
  (msg.includes('humor') || msg.includes('seriedade') || msg.includes('sério') || msg.includes('serio') || msg.includes('personalidade'))
  && (msg.includes('aument') || msg.includes('diminui') || msg.includes('reduz') || msg.includes('coloca') || msg.includes('%') || /\d+/.test(msg))
);

return [{ json: { ...($input.first().json), isPersonalityCmd } }];

const staticData = $getWorkflowStaticData('global');
const msg = $input.first().json.cleanMessage.toLowerCase();

// Current level (0 = serious, 100 = very funny)
let currentLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;

// Extract percentage from message
const pctMatch = msg.match(/(\d+)\s*%/);
const numMatch = msg.match(/(\d+)/);
const pct = pctMatch ? parseInt(pctMatch[1]) : (numMatch ? parseInt(numMatch[1]) : 20);

let newLevel = currentLevel;
let action = '';

if (msg.includes('aument') || msg.includes('mais')) {
  newLevel = Math.min(100, currentLevel + pct);
  action = 'aumentado';
} else if (msg.includes('diminui') || msg.includes('reduz') || msg.includes('menos')) {
  newLevel = Math.max(0, currentLevel - pct);
  action = 'reduzido';
} else if (msg.includes('coloca') || msg.includes('define') || msg.includes('set')) {
  newLevel = Math.min(100, Math.max(0, pct));
  action = 'definido para';
}

staticData.humorLevel = newLevel;

const levelDesc = newLevel <= 20 ? 'muito sério' : newLevel <= 40 ? 'sério' : newLevel <= 60 ? 'equilibrado' : newLevel <= 80 ? 'descontraído' : 'bem humorado';

return [{ json: {
  waChatId: $input.first().json.waChatId,
  reply: `✅ Nível de humor ${action}: ${newLevel}% (${levelDesc}). Ajuste aplicado.`
}}];

const staticData = $getWorkflowStaticData('global');
staticData.groupMemory = staticData.groupMemory || {};

const humorLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;
const pm = $('Check Personality Command').first().json;
const chatId = pm.chatId || pm.waChatId || 'unknown';

if (!staticData.groupMemory[chatId]) {
  staticData.groupMemory[chatId] = {
    messages: [],
    lastProjectId: null,
    lastProjectName: '',
    pendingTask: null,
    pendingTicket: null,
  };
}
const chatMemory = staticData.groupMemory[chatId];

const GROUP_KNOWLEDGE = {
  garlic: {
    default_client: "Garlic'n Lemons",
    canonical_project: "Garlic'n Lemons SaaS",
    aliases: ["gnl", "garlic", "garlic n lemons", "garlic'n lemons", "gnl system", "gnl-backend", "gnl-pickup", "gnl-catering"],
    systems: ["backend", "website", "pickup", "catering"],
    intent_hint: "Neste grupo, task/ticket normalmente é do projeto Garlic'n Lemons."
  },
  ernesto: {
    default_client: "Ernesto's Pizza",
    canonical_project: "Ernestos Pizza System",
    aliases: ["ernestos", "ernesto's pizza", "north end", "somerville", "fax bridge"],
    systems: ["backend", "website", "pickup", "catering"],
    intent_hint: "Neste grupo, task/ticket normalmente é do projeto Ernesto's Pizza."
  },
  angelfly: {
    default_client: "Angel Fly",
    canonical_project: "Angel Fly Cockpit",
    aliases: ["cockpit", "jarvis", "angelfly"],
    systems: ["cockpit", "n8n", "automation"],
    intent_hint: "Neste grupo, pedidos geralmente são internos/operacionais da Angel Fly."
  }
};

const extractMessages = (raw) => {
  if (!raw) return [];
  return Array.isArray(raw) ? raw :
    Array.isArray(raw?.messages) ? raw.messages :
    Array.isArray(raw?.data?.messages) ? raw.data.messages :
    Array.isArray(raw?.data?.data?.messages) ? raw.data.data.messages :
    Array.isArray(raw?.data) ? raw.data :
    Array.isArray(raw?.result?.messages) ? raw.result.messages :
    [];
};

const extractText = (m) => (
  m?.text || m?.body || m?.messageText ||
  m?.content?.conversation || m?.content?.extendedTextMessage?.text ||
  m?.message?.conversation || m?.message?.extendedTextMessage?.text || ''
).trim();

let historyText = '';
try {
  const historyData = $('Debug History').first().json;
  let msgs = historyData?._extractedMessages || [];

  if (msgs.length === 0) {
    const raw = $('Get Chat History').first().json;
    msgs = extractMessages(raw);
  }

  const inboundText = (pm.cleanMessage || pm.rawMessage || '').trim();
  if (inboundText) {
    const last = chatMemory.messages?.[chatMemory.messages.length - 1];
    if (!last || last.text !== inboundText) {
      chatMemory.messages.push({
        senderName: pm.senderName || 'Membro',
        text: inboundText,
        fromMe: false,
        ts: Date.now(),
      });
    }
  }

  if (Array.isArray(chatMemory.messages) && chatMemory.messages.length > 150) {
    chatMemory.messages = chatMemory.messages.slice(-150);
  }

  const memoryMsgs = Array.isArray(chatMemory.messages) ? chatMemory.messages : [];
  const combined = [...msgs, ...memoryMsgs];

  const lines = combined
    .map(m => ({
      name: m.fromMe ? 'ANGELFLY (Jarvis)' : (m.senderName || m.pushName || m.name || 'Membro'),
      txt: extractText(m),
    }))
    .filter(x => x.txt && x.txt.length > 0)
    .slice(-100)
    .map(x => '[' + x.name + ']: ' + x.txt);

  historyText = lines.length > 0
    ? lines.join('\n')
    : '(histórico não disponível - responda com base na mensagem atual)';
} catch (e) {
  historyText = '(erro ao carregar histórico)';
}

let projectsList = [];
let projectsRef = '  (nenhum projeto cadastrado)';
try {
  const fetchItems = $('Fetch Projects').all();
  const directRows = fetchItems.map(i => i.json).filter(Boolean);

  let wrappedRows = [];
  for (const row of directRows) {
    if (Array.isArray(row)) wrappedRows.push(...row);
    else if (Array.isArray(row?.data)) wrappedRows.push(...row.data);
    else if (Array.isArray(row?.projects)) wrappedRows.push(...row.projects);
    else if (Array.isArray(row?.items)) wrappedRows.push(...row.items);
  }

  const projs = wrappedRows.length > 0 ? wrappedRows : directRows;

  const seen = new Set();
  projectsList = projs
    .filter(p => p && p.id !== undefined && p.name)
    .filter(p => {
      const k = String(p.id);
      if (seen.has(k)) return false;
      seen.add(k);
      return true;
    })
    .filter(p => !p.status || ['active', 'assigned', 'in_progress', 'open'].includes(String(p.status).toLowerCase()))
    .map(p => ({ id: p.id, name: p.name, client_name: p.client_name || '' }));

  if (projectsList.length > 0) {
    projectsRef = projectsList
      .map(p => '  - id=' + p.id + ' | "' + p.name + '" | cliente: "' + p.client_name + '"')
      .join('\n');
  }
} catch (e) {
  projectsList = [];
}

let defaultProjectId = null;
let defaultProjectName = '';
if (chatMemory.lastProjectId) {
  const memProject = projectsList.find(p => String(p.id) === String(chatMemory.lastProjectId));
  if (memProject) {
    defaultProjectId = memProject.id;
    defaultProjectName = memProject.name;
  }
}

const groupKnowledge = GROUP_KNOWLEDGE[pm.groupContext] || null;
const groupKnowledgeSnippet = groupKnowledge
  ? [
      'Projeto canônico: ' + groupKnowledge.canonical_project,
      'Cliente padrão: ' + groupKnowledge.default_client,
      'Aliases: ' + groupKnowledge.aliases.join(', '),
      'Sistemas: ' + groupKnowledge.systems.join(', '),
      'Regra: ' + groupKnowledge.intent_hint
    ].join('\n')
  : 'Sem knowledge card específico para este grupo.';

const humorDesc = humorLevel <= 20 ? 'muito sério e formal, sem humor'
  : humorLevel <= 40 ? 'profissional com leveza ocasional'
  : humorLevel <= 60 ? 'equilibrado entre profissional e descontraído'
  : humorLevel <= 80 ? 'descontraído com bom humor moderado'
  : 'bem humorado e leve, com humor frequente';

return [{ json: {
  ...pm,
  humorLevel,
  humorDesc,
  projectsRef,
  projectsList: JSON.stringify(projectsList),
  historyText,
  defaultProjectId,
  defaultProjectName,
  cleanMessage: pm.cleanMessage || pm.rawMessage || '',
  groupKnowledgeSnippet,
} }];

